import{_ as t,o as e,c as r,a2 as d}from"./chunks/framework.Cr-Z7ngm.js";const b=JSON.parse('{"title":"现金","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"portfolio-and-statements/cash.md","filePath":"zh-CN/portfolio-and-statements/cash.md"}'),o={name:"portfolio-and-statements/cash.md"};function h(l,a,i,n,s,c){return e(),r("div",null,[...a[0]||(a[0]=[d('<h1 id="现金" tabindex="-1">现金 <a class="header-anchor" href="#现金" aria-label="Permalink to &quot;现金&quot;">​</a></h1><p>现金页展示账户的现金资产明细，包含各币种余额、资金操作入口和还款设置。</p><h2 id="页面入口" tabindex="-1">页面入口 <a class="header-anchor" href="#页面入口" aria-label="Permalink to &quot;页面入口&quot;">​</a></h2><p>底部导航「资产」→ 顶部切换「现金」标签。</p><h2 id="总金额卡片" tabindex="-1">总金额卡片 <a class="header-anchor" href="#总金额卡片" aria-label="Permalink to &quot;总金额卡片&quot;">​</a></h2><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>总金额</td><td>所有币种现金折算后的总价值</td></tr><tr><td>各币种余额</td><td>分别列出 HKD、USD 等各币种的实际余额</td></tr><tr><td>折算汇率</td><td>用于计算总金额的参考汇率</td></tr></tbody></table><p>总金额按实时汇率展示，为参考值，不代表真实兑换，可能因汇率差略有偏差。</p><h2 id="操作按钮" tabindex="-1">操作按钮 <a class="header-anchor" href="#操作按钮" aria-label="Permalink to &quot;操作按钮&quot;">​</a></h2><table tabindex="0"><thead><tr><th>按钮</th><th>功能</th></tr></thead><tbody><tr><td>转入</td><td>从外部银行账户入金</td></tr><tr><td>转出</td><td>提取资金到绑定银行账户</td></tr><tr><td>换汇</td><td>在不同币种之间进行兑换</td></tr><tr><td>存入</td><td>将现金存入余额通等理财产品</td></tr></tbody></table><h2 id="余额通入口" tabindex="-1">余额通入口 <a class="header-anchor" href="#余额通入口" aria-label="Permalink to &quot;余额通入口&quot;">​</a></h2><p>现金页提供余额通的快速入口，可一键跳转查看余额通持有情况或追加申购。详见<a href="/funds-and-wealth/余额通/香港余额通">香港余额通</a>。</p><h2 id="自动还款" tabindex="-1">自动还款 <a class="header-anchor" href="#自动还款" aria-label="Permalink to &quot;自动还款&quot;">​</a></h2><p>开启自动还款后，账户产生融资欠款时会自动使用现金余额（或赎回余额通）归还，避免额外利息产生。</p><p><strong>特殊情况</strong>：香港公共假期而美股正常开市时，余额通资金不会自动赎回。如当期交易美股产生欠款，会计息至假期结束后自动补平，期间 App 内不显示欠款，可查看结单。</p><h2 id="字段详细说明" tabindex="-1">字段详细说明 <a class="header-anchor" href="#字段详细说明" aria-label="Permalink to &quot;字段详细说明&quot;">​</a></h2><h3 id="现金可提-最大可提" tabindex="-1">现金可提（最大可提） <a class="header-anchor" href="#现金可提-最大可提" aria-label="Permalink to &quot;现金可提（最大可提）&quot;">​</a></h3><p>账户内现金及余额通按实时汇率折算后可用于交易或出金的资金。开启余额通后，该字段标注为「最大可提」。</p><h3 id="入金未到账" tabindex="-1">入金未到账 <a class="header-anchor" href="#入金未到账" aria-label="Permalink to &quot;入金未到账&quot;">​</a></h3><p>入金操作后在途、尚未到达长桥账户的资金金额。</p><h3 id="结算中-待结算资金" tabindex="-1">结算中 / 待结算资金 <a class="header-anchor" href="#结算中-待结算资金" aria-label="Permalink to &quot;结算中 / 待结算资金&quot;">​</a></h3><p>买卖股票已成交但未完成交收的金额：</p><ul><li>港股：T+2 交收</li><li>美股：T+1 交收</li></ul><p>待结算资金可用于同市场交易，但无法出金或货币兑换。</p><h3 id="冻结中-冻结资金" tabindex="-1">冻结中 / 冻结资金 <a class="header-anchor" href="#冻结中-冻结资金" aria-label="Permalink to &quot;冻结中 / 冻结资金&quot;">​</a></h3><p>因挂单、手续费、空头持仓担保金等原因被冻结的资金，包含静态冻结（交易费用、待扣利息等）和动态冻结（随空头持仓市值变动的平仓担保金）。</p><p>一笔订单多次成交可能出现多次冻结，但最终只按实际一笔订单扣费。佣金会按标准费率先冻结，活动减免后实际扣费更少。</p>',26)])])}const u=t(o,[["render",h]]);export{b as __pageData,u as default};
